async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  let logs = 4;
  let attempts = 0;

  while (logs < 10 && attempts < 30) {
    attempts++;

    // Check HP first
    const hp = await page.evaluate(() => window.__latestGameState.player_stats.hp);
    const max_hp = await page.evaluate(() => window.__latestGameState.player_stats.max_hp);

    if (hp / max_hp < 0.4) {
      return 'HP critical: ' + hp + '/' + max_hp + ' after ' + attempts + ' attempts, logs: ' + logs;
    }

    // Find nearest on-screen oak
    const oak = await page.evaluate(() => {
      const s = window.__latestGameState;
      const oaks = s.nearby_entities.filter(e => e.name === 'Oak' && e.on_screen && e.click_x > 0);
      return oaks.length > 0 ? {cx: oaks[0].click_x, cy: oaks[0].click_y} : null;
    });

    if (oak && oak.cx > 0) {
      await click(oak.cx, Math.max(oak.cy || 280, 200));
    } else {
      // Use known good spot
      await click(592, 280);
    }
    await page.waitForTimeout(3500);

    logs = await page.evaluate(() => window.__latestGameState.inventory.filter(i=>i.key==='logs').reduce((a,b)=>a+b.count,0));
    console.log('Logs: ' + logs + ' HP: ' + hp);
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({logs: s.inventory.filter(i=>i.key==='logs').reduce((a,b)=>a+b.count,0), hp: s.player_stats.hp, max_hp: s.player_stats.max_hp, pos: s.player_position});
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return finalState;
}

