    [275, 290],   // tree top-left
    [245, 450],   // tree left with batterfly
    [1160, 195],  // tree top-right
    [290, 350],   // trunk area left tree
    [250, 380],   // another left spot
  ];

  for (const [x, y] of treeSpots) {
    if (logs >= 10) break;

    await click(x, y);
    await page.waitForTimeout(3500);

    const newLogs = await page.evaluate(() => window.__latestGameState.inventory.filter(i=>i.key==='logs').reduce((a,b)=>a+b.count,0));
    if (newLogs > logs) {
      logs = newLogs;
      console.log('Got log! Total: ' + logs + ' at ' + x + ',' + y);
    }
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({logs: s.inventory.filter(i=>i.key==='logs').reduce((a,b)=>a+b.count,0), hp: s.player_stats.hp, pos: s.player_position});
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return finalState;
}

